const express = require('express');
const app = express();

// Basic routes
app.get('/', (req, res) => {
  res.send('Home page');
});

// Route parameters
app.get('/users/:id', (req, res) => {
  res.json({ userId: req.params.id });
});

// Multiple parameters
app.get('/users/:userId/posts/:postId', (req, res) => {
  const { userId, postId } = req.params;
  res.json({ userId, postId });
});

// Query strings: /search?q=hello&page=2
app.get('/search', (req, res) => {
  const { q, page = 1 } = req.query;
  res.json({ query: q, page: Number(page) });
});

// Regex routes: only numeric IDs
app.get('/items/:id(\\d+)', (req, res) => {
  res.json({ id: Number(req.params.id) });
});

// Router for grouping
const router = express.Router();
router.get('/', (req, res) => res.json({ list: [] }));
router.post('/', (req, res) => res.status(201).json(req.body));
router.get('/:id', (req, res) => res.json({ id: req.params.id }));
router.put('/:id', (req, res) => res.json({ updated: true }));
router.delete('/:id', (req, res) => res.status(204).end());
app.use('/api/v1/todos', router);

// Route prefixing
const v1 = express.Router();
const v2 = express.Router();
v1.get('/users', (req, res) => res.json({ version: 1 }));
v2.get('/users', (req, res) => res.json({ version: 2 }));
app.use('/api/v1', v1);
app.use('/api/v2', v2);

app.listen(3000);
