const express = require('express');
const app = express();

// Global middleware — runs on every request
app.use((req, res, next) => {
  req.requestId = Math.random().toString(36).slice(2);
  req.startTime = Date.now();
  next();
});

// Logging middleware
app.use((req, res, next) => {
  res.on('finish', () => {
    console.log(`[${req.requestId}] ${req.method} ${req.url} ${res.statusCode} ${Date.now() - req.startTime}ms`);
  });
  next();
});

// Conditional middleware
app.use('/api', (req, res, next) => {
  // Only runs for /api/* routes
  res.setHeader('X-API-Version', '1.0');
  next();
});

// Route-specific middleware
function requireAuth(req, res, next) {
  if (!req.headers.authorization) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  req.user = { id: 1, role: 'admin' };
  next();
}

function requireRole(...roles) {
  return (req, res, next) => {
    if (!roles.includes(req.user?.role)) {
      return res.status(403).json({ error: 'Forbidden' });
    }
    next();
  };
}

// Public route
app.get('/health', (req, res) => res.json({ ok: true }));

// Protected route with role check
app.get('/admin', requireAuth, requireRole('admin'), (req, res) => {
  res.json({ message: 'Welcome, admin' });
});

// Multiple handlers per route
app.post('/users',
  (req, res, next) => { console.log('Step 1: Validate'); next(); },
  (req, res, next) => { console.log('Step 2: Transform'); next(); },
  (req, res) => { res.json({ created: true }); }
);

app.listen(3000);
