const express = require('express');
const app = express();

app.use(express.json());

// Custom error hierarchy
class AppError extends Error {
  constructor(message, statusCode, code) {
    super(message);
    this.statusCode = statusCode;
    this.code = code;
    this.isOperational = true;
  }
}

class NotFoundError extends AppError {
  constructor(resource) {
    super(`${resource} not found`, 404, 'NOT_FOUND');
  }
}

class ValidationError extends AppError {
  constructor(fields) {
    super('Validation failed', 400, 'VALIDATION_ERROR');
    this.fields = fields;
  }
}

// Async wrapper — catches rejected promises
const wrap = (fn) => (req, res, next) => {
  Promise.resolve(fn(req, res, next)).catch(next);
};

// Routes
app.get('/users/:id', wrap(async (req, res) => {
  const user = await db.findUser(req.params.id);
  if (!user) throw new NotFoundError('User');
  res.json(user);
}));

app.post('/users', wrap(async (req, res) => {
  const { name, email } = req.body;
  const errors = {};
  if (!name) errors.name = 'Required';
  if (!email?.includes('@')) errors.email = 'Invalid email';
  if (Object.keys(errors).length) throw new ValidationError(errors);
  const user = await db.createUser({ name, email });
  res.status(201).json(user);
}));

// 404 handler — after all routes
app.use((req, res) => {
  res.status(404).json({ error: { code: 'NOT_FOUND', message: `${req.method} ${req.url} not found` } });
});

// Global error handler — LAST
app.use((err, req, res, next) => {
  const status = err.statusCode || 500;
  const response = {
    error: {
      code: err.code || 'INTERNAL_ERROR',
      message: err.isOperational ? err.message : 'Something went wrong',
    }
  };
  if (err.fields) response.error.fields = err.fields;
  if (!err.isOperational) console.error('Unexpected error:', err);
  res.status(status).json(response);
});

app.listen(3000);
